import anthropic, json
from sentence_transformers import SentenceTransformer
import numpy as np

# --- Offline: build a tiny in-memory vector store ---
model = SentenceTransformer("all-MiniLM-L6-v2")

DOCS = [
    {"id": "doc1", "text": "The remote work policy allows up to 3 days per week from home."},
    {"id": "doc2", "text": "Annual leave is 25 days per year for all full-time employees."},
    {"id": "doc3", "text": "Performance reviews are held twice a year, in June and December."},
]

embeddings = np.array([model.encode(d["text"]) for d in DOCS])

def search_docs(query: str, top_k: int = 2) -> list[dict]:
    q_emb = model.encode(query)
    scores = (embeddings @ q_emb) / (
        np.linalg.norm(embeddings, axis=1) * np.linalg.norm(q_emb) + 1e-9
    )
    top = np.argsort(scores)[::-1][:top_k]
    return [{"id": DOCS[i]["id"], "text": DOCS[i]["text"], "score": float(scores[i])} for i in top]

# --- Online: use search_docs as a Claude tool ---
client = anthropic.Anthropic()

SEARCH_TOOL = {
    "name": "search_docs",
    "description": "Search company documents for relevant information.",
    "input_schema": {
        "type": "object",
        "properties": {"query": {"type": "string"}},
        "required": ["query"]
    }
}

messages = [{"role": "user", "content": "How many days annual leave do employees get?"}]

while True:
    resp = client.messages.create(
        model="claude-sonnet-4-6",
        max_tokens=1024,
        tools=[SEARCH_TOOL],
        messages=messages
    )
    messages.append({"role": "assistant", "content": resp.content})

    if resp.stop_reason == "end_turn":
        for b in resp.content:
            if b.type == "text":
                print(b.text)
        break

    results = []
    for b in resp.content:
        if b.type == "tool_use" and b.name == "search_docs":
            hits = search_docs(**b.input)
            results.append({
                "type": "tool_result",
                "tool_use_id": b.id,
                "content": json.dumps(hits)
            })
    messages.append({"role": "user", "content": results})

from openai import OpenAI

client = OpenAI()
vector_store_id = "vs_abc123"

# Attach metadata when uploading a file
with open("q1_report.pdf", "rb") as fh:
    uploaded = client.files.create(file=fh, purpose="assistants")

# Add the file to the vector store with metadata
client.beta.vector_stores.files.create(
    vector_store_id=vector_store_id,
    file_id=uploaded.id,
    attributes={"department": "finance", "quarter": "Q1", "year": "2024"}
)

# Query with a metadata filter — only finance docs from Q1 2024
response = client.responses.create(
    model="gpt-4o",
    tools=[{
        "type": "file_search",
        "vector_store_ids": [vector_store_id],
        "filters": {
            "type": "and",
            "filters": [
                {"type": "eq", "key": "department", "value": "finance"},
                {"type": "eq", "key": "quarter",    "value": "Q1"}
            ]
        }
    }],
    input="Summarise the key financial metrics for Q1 2024."
)

for item in response.output:
    if item.type == "message":
        for block in item.content:
            if block.type == "output_text":
                print(block.text)

