from openai import OpenAI
import json

client = OpenAI()
vector_store_id = "vs_abc123"

TOOLS = [
    # Hosted file search
    {
        "type": "file_search",
        "vector_store_ids": [vector_store_id]
    },
    # Custom live-data tool
    {
        "type": "function",
        "function": {
            "name": "get_current_headcount",
            "description": "Return the current headcount for a department.",
            "parameters": {
                "type": "object",
                "properties": {"department": {"type": "string"}},
                "required": ["department"]
            }
        }
    }
]

def get_current_headcount(department: str) -> dict:
    data = {"engineering": 120, "finance": 45, "marketing": 30}
    return {"department": department, "headcount": data.get(department.lower(), 0)}

messages = [{"role": "user", "content": "What's the leave policy, and how many people are in engineering?"}]

while True:
    response = client.chat.completions.create(
        model="gpt-4o",
        messages=messages,
        tools=TOOLS
    )
    choice = response.choices[0]
    messages.append(choice.message)

    if choice.finish_reason == "stop":
        print(choice.message.content)
        break

    for tc in (choice.message.tool_calls or []):
        if tc.function.name == "get_current_headcount":
            args = json.loads(tc.function.arguments)
            result = get_current_headcount(**args)
            messages.append({
                "role": "tool",
                "tool_call_id": tc.id,
                "content": json.dumps(result)
            })
